import face_recognition
from flask import Flask, request, jsonify
from PIL import Image
import numpy as np
import os

app = Flask(__name__)

# Load employee photos and encode them into arrays
def load_employee_photos():
    employees = {}
    for file in os.listdir('employee_photos'):
        image = face_recognition.load_image_file(os.path.join('employee_photos', file))
        encoding = face_recognition.face_encodings(image)[0]
        employees[file.split('.')[0]] = encoding
    return employees

# Train model on employee photos
employees = load_employee_photos()

# API endpoint to get confidence scores for all training classes
@app.route('/confidence_scores', methods=['GET'])
def get_confidence_scores():
    image_path = request.args.get('image_path')
    image = face_recognition.load_image_file(image_path)
    encodings = face_recognition.face_encodings(image)

    if not encodings:
        return jsonify({'error': 'No faces detected'})

    confidence_scores = {}
    for employee, encoding in employees.items():
        scores = face_recognition.compare_faces([encoding], encodings[0])
        confidence_scores[employee] = scores[0]

    return jsonify(confidence_scores)

# API endpoint to get detailed probability distribution over all known faces
@app.route('/probability_distribution', methods=['GET'])
def get_probability_distribution():
    image_path = request.args.get('image_path')
    image = face_recognition.load_image_file(image_path)
    encodings = face_recognition.face_encodings(image)

    if not encodings:
        return jsonify({'error': 'No faces detected'})

    probability_distribution = {}
    for employee, encoding in employees.items():
        scores = face_recognition.compare_faces([encoding], encodings[0])
        probability_distribution[employee] = scores[0]

    return jsonify(probability_distribution)

if __name__ == '__main__':
    app.run(debug=True)